class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        for (int i = 0; i < s.size(); i++) {
            if (s[i] != target[i]) {
                for (int j = i + 1; j < s.size(); j++) {
                    if (s[i] != target[j] && s[j] != target[i]) {
                        return true;
                    }
                }
                return false;
            }
        }
        return true;
    }
};
